def build_tree_from_string(sequence):
    root = None
    def insert_recursive(node, char):
        if node is None:
            return {'char': char.lower(), 'left': None, 'right': None}
        if char.lower() < node['char']:
            node['left'] = insert_recursive(node['left'], char)
        elif char.lower() > node['char']:
            node['right'] = insert_recursive(node['right'], char)
        return node
    for char in sequence:
        root = insert_recursive(root, char)
    return root

